            CREATE OR REPLACE FUNCTION sync_module_crf_to_crf()
            RETURNS TRIGGER AS $$
            BEGIN
                IF pg_trigger_depth() > 1 THEN
                    RETURN COALESCE(NEW, OLD);
                END IF;

                IF (TG_OP = 'INSERT') THEN
                    INSERT INTO crf (
                        crf_id, name, description, oc_oid, status_id,
                        owner_id, source_study_id, date_created, date_updated, update_id
                    )
                    VALUES (
                        NEW.crf_id, NEW.name, NEW.description, NEW.oc_oid, NEW.status_id,
                        NEW.owner_id, NEW.source_study_id, NEW.date_created, NEW.date_updated, NEW.update_id
                    )
                    ON CONFLICT (crf_id) DO UPDATE SET
                        name = EXCLUDED.name,
                        description = EXCLUDED.description,
                        oc_oid = EXCLUDED.oc_oid,
                        status_id = EXCLUDED.status_id,
                        owner_id = EXCLUDED.owner_id,
                        source_study_id = EXCLUDED.source_study_id,
                        date_created = EXCLUDED.date_created,
                        date_updated = EXCLUDED.date_updated,
                        update_id = EXCLUDED.update_id;
                    RETURN NEW;
                ELSIF (TG_OP = 'UPDATE') THEN
                    UPDATE crf SET
                        name = NEW.name,
                        description = NEW.description,
                        oc_oid = NEW.oc_oid,
                        status_id = NEW.status_id,
                        owner_id = NEW.owner_id,
                        source_study_id = NEW.source_study_id,
                        date_created = NEW.date_created,
                        date_updated = NEW.date_updated,
                        update_id = NEW.update_id
                    WHERE crf_id = OLD.crf_id;
                    RETURN NEW;
                ELSIF (TG_OP = 'DELETE') THEN
                    DELETE FROM crf WHERE crf_id = OLD.crf_id;
                    RETURN OLD;
                END IF;
            END;
            $$ LANGUAGE plpgsql;

            CREATE OR REPLACE FUNCTION sync_crf_to_module_crf()
            RETURNS TRIGGER AS $$
            BEGIN
                IF pg_trigger_depth() > 1 THEN
                    RETURN COALESCE(NEW, OLD);
                END IF;

                IF (TG_OP = 'INSERT') THEN
                    INSERT INTO module_crf (
                        crf_id, name, description, oc_oid, status_id,
                        owner_id, source_study_id, date_created, date_updated, update_id
                    )
                    VALUES (
                        NEW.crf_id, NEW.name, NEW.description, NEW.oc_oid, NEW.status_id,
                        NEW.owner_id, NEW.source_study_id, NEW.date_created, NEW.date_updated, NEW.update_id
                    )
                    ON CONFLICT (crf_id) DO UPDATE SET
                        name = EXCLUDED.name,
                        description = EXCLUDED.description,
                        oc_oid = EXCLUDED.oc_oid,
                        status_id = EXCLUDED.status_id,
                        owner_id = EXCLUDED.owner_id,
                        source_study_id = EXCLUDED.source_study_id,
                        date_created = EXCLUDED.date_created,
                        date_updated = EXCLUDED.date_updated,
                        update_id = EXCLUDED.update_id;
                    RETURN NEW;
                ELSIF (TG_OP = 'UPDATE') THEN
                    UPDATE module_crf SET
                        name = NEW.name,
                        description = NEW.description,
                        oc_oid = NEW.oc_oid,
                        status_id = NEW.status_id,
                        owner_id = NEW.owner_id,
                        source_study_id = NEW.source_study_id,
                        date_created = NEW.date_created,
                        date_updated = NEW.date_updated,
                        update_id = NEW.update_id
                    WHERE crf_id = OLD.crf_id;
                    RETURN NEW;
                ELSIF (TG_OP = 'DELETE') THEN
                    DELETE FROM module_crf WHERE crf_id = OLD.crf_id;
                    RETURN OLD;
                END IF;
            END;
            $$ LANGUAGE plpgsql;

            DROP TRIGGER IF EXISTS trg_sync_module_crf ON module_crf;
            CREATE TRIGGER trg_sync_module_crf
            AFTER INSERT OR UPDATE OR DELETE ON module_crf
            FOR EACH ROW EXECUTE FUNCTION sync_module_crf_to_crf();

            DROP TRIGGER IF EXISTS trg_sync_crf_to_module ON crf;
            CREATE TRIGGER trg_sync_crf_to_module
            AFTER INSERT OR UPDATE OR DELETE ON crf
            FOR EACH ROW EXECUTE FUNCTION sync_crf_to_module_crf();

