DROP TRIGGER IF EXISTS trg_sync_crf_version_to_module ON crf_version; CREATE TRIGGER trg_sync_crf_version_to_module AFTER INSERT OR UPDATE OR DELETE ON crf_version FOR EACH ROW EXECUTE FUNCTION sync_crf_version_to_module_crf_version();

