CREATE OR REPLACE FUNCTION sync_module_section_to_section() RETURNS TRIGGER AS $$ BEGIN IF pg_trigger_depth() > 1 THEN RETURN COALESCE(NEW, OLD); END IF;
IF (TG_OP = 'INSERT') THEN INSERT INTO section ( section_id, crf_version_id, label, title, subtitle, instructions, ordinal, parent_id, status_id, owner_id, date_created, date_updated, update_id, borders, page_number_label ) VALUES ( NEW.section_id, NEW.crf_version_id, NEW.label, NEW.title, NEW.subtitle, NEW.instructions, NEW.ordinal, NEW.parent_id, NEW.status_id, NEW.owner_id, NEW.date_created, NEW.date_updated, NEW.update_id, NEW.borders, NEW.page_number_label ) ON CONFLICT (section_id) DO UPDATE SET crf_version_id = EXCLUDED.crf_version_id, label = EXCLUDED.label, title = EXCLUDED.title, subtitle = EXCLUDED.subtitle, instructions = EXCLUDED.instructions, ordinal = EXCLUDED.ordinal, parent_id = EXCLUDED.parent_id, status_id = EXCLUDED.status_id, owner_id = EXCLUDED.owner_id, date_created = EXCLUDED.date_created, date_updated = EXCLUDED.date_updated, update_id = EXCLUDED.update_id, borders = EXCLUDED.borders, page_number_label = EXCLUDED.page_number_label; RETURN NEW; ELSIF (TG_OP = 'UPDATE') THEN UPDATE section SET crf_version_id = NEW.crf_version_id, label = NEW.label, title = NEW.title, subtitle = NEW.subtitle, instructions = NEW.instructions, ordinal = NEW.ordinal, parent_id = NEW.parent_id, status_id = NEW.status_id, owner_id = NEW.owner_id, date_created = NEW.date_created, date_updated = NEW.date_updated, update_id = NEW.update_id, borders = NEW.borders, page_number_label = NEW.page_number_label WHERE section_id = OLD.section_id; RETURN NEW; ELSIF (TG_OP = 'DELETE') THEN DELETE FROM section WHERE section_id = OLD.section_id; RETURN OLD; END IF; END; $$ LANGUAGE plpgsql;
